Here's a minimal API endpoint handling multipart form uploads with multiple images and a description:

```csharp
// Program.cs

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size (default is ~30 MB)
builder.WebHost.ConfigureKestrel(o => o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Read the multipart form with a 50 MB limit
    var form = await request.ReadFormAsync(new FormOptions
    {
        MultipartBodyLengthLimit = 50 * 1024 * 1024
    });

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images"); // matches <input name="images" />

    if (files.Count == 0)
        return Results.BadRequest("No images provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var dest = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(dest);
        await file.CopyToAsync(stream);
        saved.Add(dest);
    }

    return Results.Ok(new { description, fileCount = saved.Count, paths = saved });
})
.DisableAntiforgery();          // required for minimal APIs accepting forms without a token
                                 // remove this and add antiforgery if the caller supports it

app.Run();
```

**Key points:**

- **Kestrel limit** — `MaxRequestBodySize` must be raised; the default (~28.6 MB) would reject 50 MB uploads.
- **`FormOptions.MultipartBodyLengthLimit`** — controls the per-field/file ceiling inside the multipart parser.
- **`form.Files.GetFiles("images")`** — pulls all files submitted under the `images` field name.
- **`DisableAntiforgery()`** — needed when there's no antiforgery token (e.g., API clients, Postman). Drop it and wire up antiforgery for browser forms.

A matching HTML form would look like:

```html
<form action="/upload" method="post" enctype="multipart/form-data">
  <input type="text"  name="description" />
  <input type="file"  name="images" multiple accept="image/*" />
  <button type="submit">Upload</button>
</form>
```
